// Identical logic to production mvp001 Prepare AI Prompt node
const from = ($json.body?.From || $json.From || '').toString();
const to = ($json.body?.To || $json.To || '').toString();
const text = ($json.body?.Body || $json.Body || '').toString().trim();
const messageSid = ($json.body?.MessageSid || $json.MessageSid || 'SMdemo').toString();
const profileName = ($json.body?.ProfileName || $json.ProfileName || '').toString();

const bookingIntent = /(book|appointment|schedule|tomorrow|today|monday|tuesday|wednesday|thursday|friday|saturday|am|pm|oil|brake|tires?|diagnostic|repair|service)/i.test(text);

let serviceType = 'general service';
if (/oil/i.test(text)) serviceType = 'oil change';
else if (/brake/i.test(text)) serviceType = 'brake service';
else if (/tire|tyre/i.test(text)) serviceType = 'tire service';
else if (/diagnostic/i.test(text)) serviceType = 'diagnostic';
else if (/battery/i.test(text)) serviceType = 'battery service';
else if (/engine/i.test(text)) serviceType = 'engine repair';

const currentDate = new Date().toISOString();

const systemPrompt = `You are AutoShop AI, an SMS booking assistant for an auto repair shop.\nYour job:\n1. Reply like a real service advisor by SMS.\n2. Be concise, helpful, and natural.\n3. If the customer wants to book, collect missing info.\n4. Extract booking info when present.\n5. Never use markdown.\n6. Return STRICT JSON only.\n\nBusiness context:\n- Shop name: AutoShop AI\n- Channel: SMS\n- Goal: convert inbound SMS into appointment booking\n- Timezone: America/Chicago\n- Current timestamp: ${currentDate}\n\nReturn JSON exactly in this shape:\n{\n  "reply_text": "string",\n  "booking_intent": true,\n  "customer_name": "string",\n  "service_type": "string",\n  "requested_time_text": "string",\n  "needs_more_info": true,\n  "calendar_summary": "string",\n  "calendar_description": "string"\n}\n\nRules:\n- booking_intent = true if the person appears to want service or scheduling.\n- If date/time is unclear, ask for it in reply_text and set needs_more_info = true.\n- If service type is unclear, ask for it.\n- Keep reply_text short enough for SMS.\n- calendar_summary should be short.\n- calendar_description should include the original SMS.`;

const userPrompt = `Inbound customer SMS:\nFrom: ${from}\nProfile Name: ${profileName}\nMessage: ${text}\n\nHeuristic booking intent: ${bookingIntent}\nHeuristic service type: ${serviceType}`;

// Build credentials exactly as production does
const openaiKey = $env.OPENAI_API_KEY || '';
const twilioSid = $env.TWILIO_ACCOUNT_SID || '';
const twilioToken = $env.TWILIO_AUTH_TOKEN || '';
const twilioMsgSid = $env.TWILIO_MESSAGING_SERVICE_SID || '';
const twilioAuth = 'Basic ' + Buffer.from(twilioSid + ':' + twilioToken).toString('base64');

return [{
  json: {
    from,
    to,
    body: text,
    message_sid: messageSid,
    booking_intent_heuristic: bookingIntent,
    service_type_heuristic: serviceType,
    openai_system_prompt: systemPrompt,
    openai_user_prompt: userPrompt,
    openai_bearer: 'Bearer ' + openaiKey,
    twilio_auth: twilioAuth,
    twilio_sid: twilioSid,
    twilio_msg_sid: twilioMsgSid
  }
}];

// Identical to production Parse AI JSON
const raw = $json.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    reply_text: 'Thanks for contacting AutoShop AI. What service do you need and what day/time works for you?',
    booking_intent: true,
    customer_name: '',
    service_type: 'general service',
    requested_time_text: '',
    needs_more_info: true,
    calendar_summary: 'AutoShop appointment inquiry',
    calendar_description: `Raw AI parse failed. Original response: ${raw}`
  };
}

const base = $('Prepare AI Prompt').first().json;

return [{
  json: {
    ...base,
    ai_raw: raw,
    reply_text: parsed.reply_text || 'Thanks for contacting AutoShop AI. What service do you need?',
    booking_intent: !!parsed.booking_intent,
    customer_name: parsed.customer_name || '',
    service_type: parsed.service_type || base.service_type_heuristic || 'general service',
    requested_time_text: parsed.requested_time_text || '',
    needs_more_info: parsed.needs_more_info !== undefined ? !!parsed.needs_more_info : true,
    calendar_summary: parsed.calendar_summary || 'AutoShop appointment inquiry',
    calendar_description: parsed.calendar_description || ''
  }
}];

// Create a real Google Calendar event when booking info is complete.
// Requires GOOGLE_ACCESS_TOKEN in env (short-lived token from Google OAuth Playground
// or from the full OAuth flow via /auth/google/start).
//
// calendar_status values:
//   created        — event created, google_event_id + google_event_link are set
//   needs_more_info — AI says needs_more_info=true, skip calendar
//   no_token       — GOOGLE_ACCESS_TOKEN not set, skip calendar
//   api_error:...  — Google API returned error
//   error:...      — network / parse error

const ai = $json;
const accessToken = $env.GOOGLE_ACCESS_TOKEN || '';

const canBook = ai.booking_intent && !ai.needs_more_info && ai.requested_time_text;

let googleEventId = null;
let googleEventLink = null;
let calendarStatus = 'skipped';

if (canBook && accessToken) {
  try {
    // Parse requested_time_text to a Date.
    // AI returns ISO strings when it has enough info (e.g. "2026-03-08T10:00:00-06:00").
    // Fall back to tomorrow 10am CT if unparseable.
    let start = new Date(ai.requested_time_text);
    if (isNaN(start.getTime())) {
      const d = new Date();
      d.setDate(d.getDate() + 1);
      d.setHours(16, 0, 0, 0); // 10:00 CT = 16:00 UTC
      start = d;
    }
    const end = new Date(start.getTime() + 60 * 60 * 1000); // 1-hour slot

    const eventBody = {
      summary: ai.calendar_summary || (ai.service_type + ' — ' + ai.from),
      description: [
        'AutoShop AI Demo Booking',
        'Service : ' + ai.service_type,
        'Customer: ' + ai.from,
        (ai.customer_name ? 'Name    : ' + ai.customer_name : ''),
        'SMS     : ' + ai.body,
        '',
        (ai.calendar_description || '')
      ].filter(Boolean).join('\n'),
      start: { dateTime: start.toISOString(), timeZone: 'America/Chicago' },
      end:   { dateTime: end.toISOString(),   timeZone: 'America/Chicago' }
    };

    const res = await fetch(
      'https://www.googleapis.com/calendar/v3/calendars/primary/events',
      {
        method: 'POST',
        headers: {
          'Authorization': 'Bearer ' + accessToken,
          'Content-Type':  'application/json'
        },
        body: JSON.stringify(eventBody)
      }
    );

    const data = await res.json();
    if (res.ok && data.id) {
      googleEventId   = data.id;
      googleEventLink = data.htmlLink || null;
      calendarStatus  = 'created';
    } else {
      calendarStatus = 'api_error:' + (data.error?.message || String(res.status));
    }
  } catch (err) {
    calendarStatus = 'error:' + err.message;
  }
} else if (canBook && !accessToken) {
  calendarStatus = 'no_token';
} else {
  calendarStatus = 'needs_more_info';
}

return [{
  json: {
    ...$json,
    google_event_id:   googleEventId,
    google_event_link: googleEventLink,
    calendar_status:   calendarStatus
  }
}];

// Set final_reply_text and override To with demo recipient.
const DEMO_TO = '+37067577829'; // Demo recipient — real phone for live demo

return [{
  json: {
    ...$json,
    final_reply_text: $json.reply_text,
    demo_to: DEMO_TO
  }
}];

// Extract Twilio result and combine with AI + calendar output for clean demo response
const tw      = $json;
const ai      = $('Parse AI JSON').first().json;
const cal     = $('Create Google Calendar Event').first().json;
const compose = $('Compose Demo Reply').first().json;

return [{
  json: {
    demo: true,
    inbound_message:    ai.body,
    from:               ai.from,
    ai_reply:           ai.reply_text,
    booking_intent:     ai.booking_intent,
    service_type:       ai.service_type,
    requested_time_text: ai.requested_time_text || '',
    needs_more_info:    ai.needs_more_info,
    calendar_summary:   ai.calendar_summary,
    calendar_status:    cal.calendar_status || 'skipped',
    google_event_id:    cal.google_event_id   || null,
    google_event_link:  cal.google_event_link  || null,
    twilio_to:          compose.demo_to,
    twilio_message_sid: tw.sid    || null,
    twilio_status:      tw.status || null,
    twilio_error:       tw.message || null,
    model: 'gpt-4o-mini'
  }
}];
